# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

class AccountManager extends Actor {
  var balance: Double = 0.0

  def receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! BalanceUpdated(balance)

    case Withdrawal(amount) =>
      if (balance >= amount) {
        balance -= amount
        sender() ! TransactionSuccess(balance)
      } else {
        sender() ! TransactionFailure("Insufficient funds")
      }
  }
}

object AccountManagerApp extends App {
  val system = ActorSystem("AccountSystem")
  val accountManager = system.actorOf(Props[AccountManager], name = "accountManager")

  // Example usage
  import system.dispatcher

  accountManager ! Deposit(100.0)
  accountManager ! Withdrawal(50.0)
}

case class Deposit(amount: Double)
case class Withdrawal(amount: Double)
case class BalanceUpdated(balance: Double)
case class TransactionSuccess(balance: Double)
case class TransactionFailure(reason: String)